public class TypePromo {
    public static void main(String[] args) {
        int i = 1_000_000;
        int j = 1_000_000;
        long product = (long) i * j;
        System.out.println(product);
        System.out.println(i * j);   // overflow!
        System.out.println('A' + 1);
        System.out.println("" + 'A' + 1);
    }
}
